import os
import shutil
import sys

staging = "../owl-bot-staging/secretmanager/v1"
if not os.path.exists(staging):
    sys.exit(0)
for item in os.listdir(staging):
    s = os.path.join(staging, item)
    d = os.path.join(".", item)
    if os.path.isdir(s):
        if os.path.exists(d):
            shutil.rmtree(d)
        shutil.copytree(s, d)
    else:
        shutil.copy2(s, d)
